theory.syntax:
WITH ranked AS (
  SELECT columns, ROW_NUMBER() OVER (PARTITION BY group_column ORDER BY sort_column DESC) AS rn
  FROM table_name
)
SELECT * FROM ranked WHERE rn <= N;

example.query:
-- 1. Top scorer per city
WITH ranked AS (
  SELECT name, city, marks, ROW_NUMBER() OVER (PARTITION BY city ORDER BY marks DESC) AS rn
  FROM Students
)
SELECT name, city, marks FROM ranked WHERE rn = 1;

-- 2. Top 2 scorers per city
WITH ranked AS (
  SELECT name, city, marks, ROW_NUMBER() OVER (PARTITION BY city ORDER BY marks DESC) AS rn
  FROM Students
)
SELECT name, city, marks FROM ranked WHERE rn <= 2;
